import { Entity } from './Entity';

// GLOBAL_DAMPING: Air resistance and global kinetic energy loss factor per substep. 
// Increase towards 1.0 -> Log falls faster and retains momentum (more realistic). 
// Decrease towards 0.0 -> Log falls slower (slow-motion) and loses energy quickly.
const GLOBAL_DAMPING = 0.999;

// TERRAIN_ROLLING_RESISTANCE: How quickly the log stops rolling when in contact with the ground.
// Increase -> Log stops rolling sooner.
// Decrease -> Log rolls endlessly.
const TERRAIN_ROLLING_RESISTANCE = 0.05;

// TERRAIN_FRICTION: How much the log resists sliding sideways on the ground (Coulomb friction).
// Increase -> Log grips the ground more (less sliding).
// Decrease -> Log slides around like it's on ice.
const TERRAIN_FRICTION = 0.90;

export interface Spring {
  i1: number;
  i2: number;
  L0: number; // Rest length, -1 if broken/disabled
  k: number;  // Stiffness constant (0.0 to 1.0)
}

export class MassSpringLog extends Entity {
  // Config parameters
  public length = 10;
  public radius = 0.5;
  public woodDensity = 500;

  // Spring Stiffness Constants (0.0 to 1.0)
  // 1.0 = Maximum rigidity (wood-like). Lower values make the log more elastic/rubbery.
  
  // kStructural: Grain & Ring Stiffness. Connects adjacent particles.
  // Decrease -> Log acts like a bungee cord, stretching and squishing easily.
  public kStructural = 1.0;
  
  // kShear: Twist & Collapse Resistance. Diagonal cross-bracing.
  // Decrease -> Log acts like an empty cardboard tube, twisting and flattening sideways.
  public kShear = 1.0;
  
  // kBending: Flexibility. Skips adjacent rings to enforce straightness.
  // Decrease -> Log acts like a pool noodle, sagging heavily under gravity when supported at ends.
  public kBending = 1.0;
  
  public gravityY: number = -9.8;

  // Collision shape approximations
  public numRings = 0;
  public particlesPerRing = 25; // 1 pith + 8 inner + 16 outer
  public numParticles = 0;

  public positions!: Float32Array;
  public oldPositions!: Float32Array;
  public initialPositions!: Float32Array;
  public forces!: Float32Array;
  public externalForces!: Float32Array;
  public isStatic!: Uint8Array; // 1 if particle is pinned by a support, 2 if resting, 0 otherwise
  public isEndcap!: Uint8Array; // 1 if particle belongs to a kerf face, 0 otherwise
  public segmentIds!: Uint16Array;

  // Springs
  public springs: Spring[] = [];
  public activeSpringCount!: Uint8Array;
  public fractureCooldown: number = 0;

  // Spatial Hashing properties
  public cellSize = 0.5;
  public spatialHash: Map<number, number[]> = new Map();

  // Collision properties
  public particleRadius = 0.15;
  public restitution = 0.3;
  public friction = 0.6;
  public kerfCollisionMargin = 0.06;
  public collisionRamps: Array<{ x1: number, y1: number, z1: number, x2: number, y2: number, z2: number }> = [];
  public stumps: Array<{ x: number, y: number, z: number, radius: number, end_z: number, time: number }> = [];
  public elapsedTime: number = 0;
  public sleepFrames!: Uint8Array;

  public terrain: { heightmap: Float32Array; width: number; depth: number; widthSegments: number; depthSegments: number } | null = null;

  constructor(name = 'MassSpringLog') {
    super(name);
  }

  public initialize(
    length: number,
    radius: number,
    density: number,
    supports: Array<{ x: number; y: number; z: number, type?: string, lock_up_down?: boolean }>,
    center = { x: 0, y: 1, z: 0 }
  ): void {
    this.length = length;
    this.radius = radius;
    this.woodDensity = density;

    // Define rings spaced along X-axis at ~0.25m intervals
    const ringSpacing = 0.25;
    this.numRings = Math.max(3, Math.round(length / ringSpacing) + 1);
    const actualSpacing = length / (this.numRings - 1);

    this.numParticles = this.numRings * this.particlesPerRing;

    // Allocate flat arrays
    this.positions = new Float32Array(this.numParticles * 3);
    this.oldPositions = new Float32Array(this.numParticles * 3);
    this.initialPositions = new Float32Array(this.numParticles * 3);
    this.forces = new Float32Array(this.numParticles * 3);
    this.externalForces = new Float32Array(this.numParticles * 3);
    this.isStatic = new Uint8Array(this.numParticles);
    this.isEndcap = new Uint8Array(this.numParticles);
    this.segmentIds = new Uint16Array(this.numParticles);
    this.sleepFrames = new Uint8Array(this.numParticles);
    this.activeSpringCount = new Uint8Array(this.numParticles);
    this.springs = [];

    this.particleRadius = (Math.PI * radius) / 16;
    this.cellSize = this.particleRadius * 2.5;

    // Sort supports by X to interpolate log resting shape
    const sortedSupports = [...supports].sort((a, b) => a.x - b.x);

    let slopeAngle = 0;
    let y0 = 0;
    if (sortedSupports.length >= 2) {
      const s1 = sortedSupports[0];
      const s2 = sortedSupports[sortedSupports.length - 1];
      if (s2.x > s1.x) {
        const dy = s2.y - s1.y;
        const hyp = s2.x - s1.x;
        // Clamp to prevent NaN if user provides impossible slopes
        const sinTheta = Math.max(-1, Math.min(1, dy / hyp));
        slopeAngle = Math.asin(sinTheta);
        y0 = s1.y - s1.x * Math.sin(slopeAngle);
      } else {
        y0 = s1.y;
      }
    } else if (sortedSupports.length === 1) {
      y0 = sortedSupports[0].y;
    }

    // 1. Generate particle positions
    for (let r = 0; r < this.numRings; r++) {
      const localX = r * actualSpacing;

      const ringCenterX = center.x + (localX - length / 2) * Math.cos(slopeAngle);
      const ringCenterY = center.y + y0 + localX * Math.sin(slopeAngle);
      const ringCenterZ = center.z;

      // Pith (Lane 0)
      const pithIdx = (r * this.particlesPerRing) * 3;
      this.positions[pithIdx] = ringCenterX;
      this.positions[pithIdx + 1] = ringCenterY;
      this.positions[pithIdx + 2] = ringCenterZ;

      // Lane 1 (Concentric layer midway) - 8 particles
      for (let i = 0; i < 8; i++) {
        const theta = i * (Math.PI * 2 / 8);
        const yOrig = radius * 0.5 * Math.cos(theta);
        const zOrig = radius * 0.5 * Math.sin(theta);

        const pIdx = (r * this.particlesPerRing + 1 + i) * 3;
        this.positions[pIdx] = ringCenterX - yOrig * Math.sin(slopeAngle);
        this.positions[pIdx + 1] = ringCenterY + yOrig * Math.cos(slopeAngle);
        this.positions[pIdx + 2] = ringCenterZ + zOrig;
      }

      // Lane 2 (Concentric layer outer) - 16 particles
      for (let i = 0; i < 16; i++) {
        const theta = i * (Math.PI * 2 / 16);
        const yOrig = radius * Math.cos(theta);
        const zOrig = radius * Math.sin(theta);

        const pIdx = (r * this.particlesPerRing + 9 + i) * 3;
        this.positions[pIdx] = ringCenterX - yOrig * Math.sin(slopeAngle);
        this.positions[pIdx + 1] = ringCenterY + yOrig * Math.cos(slopeAngle);
        this.positions[pIdx + 2] = ringCenterZ + zOrig;
      }
    }

    // Set old and initial positions equal to initial generated positions
    this.oldPositions.set(this.positions);
    this.initialPositions.set(this.positions);

    // 2. Pin support nodes
    this.collisionRamps = [];
    this.stumps = [];
    this.elapsedTime = 0;
    supports.forEach((support: any) => {
      if (support.type === 'stump') {
        this.stumps.push({
          x: center.x + (support.x - length / 2) * Math.cos(slopeAngle),
          y: support.y,
          z: center.z + support.z,
          radius: support.radius,
          end_z: center.z + support.end_z,
          time: support.time / 1000 // Convert ms to seconds
        });
        return; // Do not pin particles for stumps
      }

      if (support.type === 'ramp' && support.collisions) {
        const wX1 = center.x + (support.x - length / 2) * Math.cos(slopeAngle);
        const wY1 = support.y;
        const wZ1 = center.z + support.z;

        const wX2 = center.x + (support.end_x - length / 2) * Math.cos(slopeAngle);
        const wY2 = support.end_y;
        const wZ2 = center.z + support.end_z;

        this.collisionRamps.push({
          x1: wX1, y1: wY1, z1: wZ1,
          x2: wX2, y2: wY2, z2: wZ2,
        });
        return; // Do not pin particles for collision ramps
      }

      let closestRingIdx = -1;
      let minXDist = Infinity;

      for (let r = 0; r < this.numRings; r++) {
        const ringLocalX = r * actualSpacing;
        const dist = Math.abs(ringLocalX - support.x);
        if (dist < minXDist) {
          minXDist = dist;
          closestRingIdx = r;
        }
      }

      // Pin the pith of the closest ring
      if (closestRingIdx !== -1) {
        const start = closestRingIdx * this.particlesPerRing;
        const pinState = support.lock_up_down === false ? 2 : 1;
        if (pinState === 1) {
          for (let k = 0; k < this.particlesPerRing; k++) {
            this.isStatic[start + k] = Math.max(this.isStatic[start + k], 1);
          }
        } else {
          // Only pin the pith to allow the ring to pitch (seesaw) naturally without exploding
          this.isStatic[start] = Math.max(this.isStatic[start], 2);
        }
      }
    });

    // Helper to add a spring
    const addSpring = (i1: number, i2: number, k: number) => {
      const idx1 = i1 * 3;
      const idx2 = i2 * 3;
      const dx = this.positions[idx1] - this.positions[idx2];
      const dy = this.positions[idx1 + 1] - this.positions[idx2 + 1];
      const dz = this.positions[idx1 + 2] - this.positions[idx2 + 2];
      const L0 = Math.sqrt(dx * dx + dy * dy + dz * dz);
      this.springs.push({ i1, i2, L0, k });
      this.activeSpringCount[i1]++;
      this.activeSpringCount[i2]++;
    };

    // 3. Connect Springs
    for (let r = 0; r < this.numRings; r++) {
      const ringOffset = r * this.particlesPerRing;

      // --- INTRA-RING ---
      // Circumferential: Lane 1 (1..8)
      for (let i = 0; i < 8; i++) {
        const next = (i + 1) % 8;
        addSpring(ringOffset + 1 + i, ringOffset + 1 + next, this.kStructural);
      }
      // Circumferential: Lane 2 (9..24)
      for (let i = 0; i < 16; i++) {
        const next = (i + 1) % 16;
        addSpring(ringOffset + 9 + i, ringOffset + 9 + next, this.kStructural);
      }
      // Radial: Pith to Lane 1
      for (let i = 0; i < 8; i++) {
        addSpring(ringOffset, ringOffset + 1 + i, this.kStructural);
      }
      // Radial: Lane 1 to Lane 2
      for (let i = 0; i < 8; i++) {
        addSpring(ringOffset + 1 + i, ringOffset + 9 + (2 * i), this.kStructural);
        addSpring(ringOffset + 1 + i, ringOffset + 9 + ((2 * i + 1) % 16), this.kStructural);
      }

      // Intra-ring Shear (Diagonal Bracing)
      for (let i = 0; i < 8; i++) {
        const next = (i + 1) % 8;
        addSpring(ringOffset + 1 + i, ringOffset + 9 + (2 * next), this.kShear);
        addSpring(ringOffset + 1 + next, ringOffset + 9 + (2 * i + 1), this.kShear);
      }

      // --- INTER-RING (LONGITUDINAL) ---
      if (r < this.numRings - 1) {
        const nextRingOffset = (r + 1) * this.particlesPerRing;

        // Grain (Structural)
        for (let i = 0; i < this.particlesPerRing; i++) {
          addSpring(ringOffset + i, nextRingOffset + i, this.kStructural);
        }

        // Shear (Diagonals)
        // 1. Intra-lane diagonals (Circumferential Shear)
        // Lane 1 diagonals
        for (let i = 0; i < 8; i++) {
          const next = (i + 1) % 8;
          addSpring(ringOffset + 1 + i, nextRingOffset + 1 + next, this.kShear);
          addSpring(ringOffset + 1 + next, nextRingOffset + 1 + i, this.kShear);
        }
        // Lane 2 diagonals
        for (let i = 0; i < 16; i++) {
          const next = (i + 1) % 16;
          addSpring(ringOffset + 9 + i, nextRingOffset + 9 + next, this.kShear);
          addSpring(ringOffset + 9 + next, nextRingOffset + 9 + i, this.kShear);
        }

        // 2. Inter-lane diagonals (Radial Shear)
        // Pith (Lane 0) <-> Lane 1
        for (let i = 0; i < 8; i++) {
          addSpring(ringOffset, nextRingOffset + 1 + i, this.kShear);
          addSpring(nextRingOffset, ringOffset + 1 + i, this.kShear);
        }
        // Lane 1 <-> Lane 2
        for (let i = 0; i < 8; i++) {
          const outer1 = 2 * i;
          const outer2 = (2 * i + 1) % 16;

          addSpring(ringOffset + 1 + i, nextRingOffset + 9 + outer1, this.kShear);
          addSpring(ringOffset + 1 + i, nextRingOffset + 9 + outer2, this.kShear);

          addSpring(nextRingOffset + 1 + i, ringOffset + 9 + outer1, this.kShear);
          addSpring(nextRingOffset + 1 + i, ringOffset + 9 + outer2, this.kShear);
        }
      }

      // --- BENDING & TORSION (SKIP-GRAIN) ---
      if (r < this.numRings - 2) {
        const skipRingOffset = (r + 2) * this.particlesPerRing;
        for (let i = 0; i < this.particlesPerRing; i++) {
          addSpring(ringOffset + i, skipRingOffset + i, this.kBending);
        }
      }
    }

    this.updateDynamicGrid();
  }

  public breakSpring(spring: Spring): void {
    if (spring.L0 < 0) return;
    spring.L0 = -1;
    if (this.activeSpringCount[spring.i1] > 0) this.activeSpringCount[spring.i1]--;
    if (this.activeSpringCount[spring.i2] > 0) this.activeSpringCount[spring.i2]--;
  }

  public setTerrain(data: any): void {
    this.terrain = data;
  }

  private sampleHeightmap(x: number, z: number): number {
    if (!this.terrain) return 0;
    const { heightmap, width, depth, widthSegments, depthSegments } = this.terrain;

    const u = (x + width / 2) / width;
    const v = (z + depth / 2) / depth;

    if (u < 0 || u >= 1 || v < 0 || v >= 1) return 0;

    const floatCol = u * widthSegments;
    const floatRow = v * depthSegments;

    const c0 = Math.floor(floatCol);
    const c1 = Math.min(c0 + 1, widthSegments);
    const r0 = Math.floor(floatRow);
    const r1 = Math.min(r0 + 1, depthSegments);

    const fu = floatCol - c0;
    const fv = floatRow - r0;

    const getH = (col: number, row: number) => heightmap[row * (widthSegments + 1) + col];

    const h00 = getH(c0, r0);
    const h10 = getH(c1, r0);
    const h01 = getH(c0, r1);
    const h11 = getH(c1, r1);

    const top = h00 * (1 - fu) + h10 * fu;
    const bot = h01 * (1 - fu) + h11 * fu;
    return top * (1 - fv) + bot * fv;
  }

  private getTerrainHeightAndNormal(x: number, z: number): { y: number, nx: number, ny: number, nz: number } {
    if (!this.terrain) return { y: 0.05, nx: 0, ny: 1, nz: 0 };

    const y = this.sampleHeightmap(x, z);
    const eps = 0.1;
    const hL = this.sampleHeightmap(x - eps, z);
    const hR = this.sampleHeightmap(x + eps, z);
    const hD = this.sampleHeightmap(x, z - eps);
    const hU = this.sampleHeightmap(x, z + eps);

    const nx = hL - hR;
    const ny = 2 * eps;
    const nz = hD - hU;

    const len = Math.sqrt(nx * nx + ny * ny + nz * nz);
    if (len === 0) return { y, nx: 0, ny: 1, nz: 0 };
    return { y, nx: nx / len, ny: ny / len, nz: nz / len };
  }

  /**
   * Verlet Integration and PBD spring relaxation step.
   */
  public lastDt = 0.00416; // 1/240 default

  public override update(subDt: number): void {
    this.integrateAndFracture(subDt);
    this.solveSprings();
  }

  public integrateAndFracture(subDt: number): void {
    if (!this.positions) return;
    this.lastDt = subDt;
    this.elapsedTime += subDt;

    if (this.fractureCooldown > 0) {
      this.fractureCooldown--;
    }

    // Global Fracture Evaluation
    let maxStretch = 0;
    let springToBreak: Spring | null = null;
    let breakInstantly = false;

    for (const spring of this.springs) {
      if (spring.L0 < 0) continue;

      const idx1 = spring.i1 * 3;
      const idx2 = spring.i2 * 3;
      const dx = this.positions[idx1] - this.positions[idx2];
      const dy = this.positions[idx1 + 1] - this.positions[idx2 + 1];
      const dz = this.positions[idx1 + 2] - this.positions[idx2 + 2];
      const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

      if (dist === 0) continue;

      const effectiveL0 = Math.max(spring.L0, 0.02);
      const stretch = dist / effectiveL0;

      // Absolute fail-safe threshold (prioritizes solver stability over orphan rule)
      if (stretch > 2.5) {
        maxStretch = stretch;
        springToBreak = spring;
        breakInstantly = true;
        break;
      }

      // Gradual fracture threshold
      if (stretch > 1.30 && stretch > maxStretch) {
        // Orphan prevention rule
        if (this.activeSpringCount[spring.i1] > 3 && this.activeSpringCount[spring.i2] > 3) {
          maxStretch = stretch;
          springToBreak = spring;
        }
      }
    }

    if (springToBreak) {
      if (breakInstantly || this.fractureCooldown <= 0) {
        this.breakSpring(springToBreak);
        this.fractureCooldown = 2; // Cooldown of 2 sub-steps
      }
    }

    // Apply gravity
    const gravityY = this.gravityY;

    // 1. Verlet Integration
    for (let i = 0; i < this.numParticles; i++) {
      if (this.isStatic[i]) continue;

      const idx = i * 3;
      const x = this.positions[idx];
      const y = this.positions[idx + 1];
      const z = this.positions[idx + 2];

      const prevX = this.oldPositions[idx];
      const prevY = this.oldPositions[idx + 1];
      const prevZ = this.oldPositions[idx + 2];

      // Verlet equations with damping
      let nextX = x + (x - prevX) * GLOBAL_DAMPING + (this.forces[idx] + this.externalForces[idx]) * subDt * subDt;
      let nextY = y + (y - prevY) * GLOBAL_DAMPING + (this.forces[idx + 1] + this.externalForces[idx + 1] + gravityY) * subDt * subDt;
      let nextZ = z + (z - prevZ) * GLOBAL_DAMPING + (this.forces[idx + 2] + this.externalForces[idx + 2]) * subDt * subDt;

      // Handle resting supports (isStatic === 2)
      if (this.isStatic[i] === 2) {
        // Act like a V-notch cradle: gently guide X and Z back to center to prevent drift
        const driftX = this.initialPositions[idx] - nextX;
        const driftZ = this.initialPositions[idx + 2] - nextZ;

        if (nextY <= this.initialPositions[idx + 1]) {
          // Hard clamp Y if it pushes into the support
          nextY = this.initialPositions[idx + 1];
          // Stronger X/Z lock when resting to prevent jiggling
          nextX += driftX * 0.8;
          nextZ += driftZ * 0.8;
        } else {
          // Soft X/Z lock when lifted off the support
          nextX += driftX * 0.1;
          nextZ += driftZ * 0.1;
        }
      }

      // Store current positions into oldPositions
      this.oldPositions[idx] = x;
      this.oldPositions[idx + 1] = y;
      this.oldPositions[idx + 2] = z;

      // Update positions
      this.positions[idx] = nextX;
      this.positions[idx + 1] = nextY;
      this.positions[idx + 2] = nextZ;

      // Reset forces
      this.forces[idx] = 0;
      this.forces[idx + 1] = 0;
      this.forces[idx + 2] = 0;
    }
  }

  public solveSprings(): void {
    if (!this.positions) return;
    // 2. PBD Constraint Solver: Spring relaxation loop (16 iterations)
    for (let iter = 0; iter < 12; iter++) {
      for (const spring of this.springs) {
        if (spring.L0 < 0) continue; // deactivated/broken spring

        const idx1 = spring.i1 * 3;
        const idx2 = spring.i2 * 3;

        const dx = this.positions[idx1] - this.positions[idx2];
        const dy = this.positions[idx1 + 1] - this.positions[idx2 + 1];
        const dz = this.positions[idx1 + 2] - this.positions[idx2 + 2];
        const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

        if (dist === 0) continue;

        const diff = (spring.L0 - dist) / dist;

        // PBD mass-weighted displacement projection (w = 1 for dynamic/resting, w = 0 for strictly pinned)
        const w1 = this.isStatic[spring.i1] === 1 ? 0 : 1;
        const w2 = this.isStatic[spring.i2] === 1 ? 0 : 1;
        const wSum = w1 + w2;
        if (wSum === 0) continue;

        const k = spring.k;

        if (w1 > 0) {
          const factor1 = (w1 / wSum) * k;
          this.positions[idx1] += dx * diff * factor1;
          this.positions[idx1 + 1] += dy * diff * factor1;
          this.positions[idx1 + 2] += dz * diff * factor1;

          if (this.isStatic[spring.i1] === 2) {
            if (this.positions[idx1 + 1] < this.initialPositions[idx1 + 1]) {
              this.positions[idx1 + 1] = this.initialPositions[idx1 + 1];
            }
          }
        }
        if (w2 > 0) {
          const factor2 = (w2 / wSum) * k;
          this.positions[idx2] -= dx * diff * factor2;
          this.positions[idx2 + 1] -= dy * diff * factor2;
          this.positions[idx2 + 2] -= dz * diff * factor2;

          if (this.isStatic[spring.i2] === 2) {
            if (this.positions[idx2 + 1] < this.initialPositions[idx2 + 1]) {
              this.positions[idx2 + 1] = this.initialPositions[idx2 + 1];
            }
          }
        }
      }
    }

    // Soft Ground collision constraint (acts like mud/dirt)
    for (let i = 0; i < this.numParticles; i++) {
      const idx = i * 3;

      const px = this.positions[idx];
      const py = this.positions[idx + 1];
      const pz = this.positions[idx + 2];

      const { y: groundLevel, nx, ny, nz } = this.getTerrainHeightAndNormal(px, pz);
      const effectiveGroundLevel = groundLevel + 0.05;

      if (py < effectiveGroundLevel) {
        const penetration = effectiveGroundLevel - py;
        this.positions[idx] += nx * penetration * 0.25;
        this.positions[idx + 1] += ny * penetration * 0.25;
        this.positions[idx + 2] += nz * penetration * 0.25;

        // Dampen downward velocity to absorb energy into the ground
        const vx = this.positions[idx] - this.oldPositions[idx];
        const vy = this.positions[idx + 1] - this.oldPositions[idx + 1];
        const vz = this.positions[idx + 2] - this.oldPositions[idx + 2];

        const velAlongNormal = vx * nx + vy * ny + vz * nz;

        if (velAlongNormal < 0) {
          this.oldPositions[idx] += nx * velAlongNormal * 0.5;
          this.oldPositions[idx + 1] += ny * velAlongNormal * 0.5;
          this.oldPositions[idx + 2] += nz * velAlongNormal * 0.5;
        }

        // Isolated Terrain Friction (Coulomb Friction Model)
        const tangX = vx - nx * velAlongNormal;
        const tangY = vy - ny * velAlongNormal;
        const tangZ = vz - nz * velAlongNormal;
        const tangLen = Math.sqrt(tangX * tangX + tangY * tangY + tangZ * tangZ);

        if (tangLen > 0.0001) {
          // Friction force is proportional to the normal force (represented by penetration push and impact)
          const normalForce = Math.max(0, -velAlongNormal) + (penetration * 0.25);
          const maxFriction = TERRAIN_FRICTION * normalForce;

          if (tangLen <= maxFriction) {
            // Static Friction: completely kill the sliding velocity
            this.positions[idx] -= tangX;
            this.positions[idx + 1] -= tangY;
            this.positions[idx + 2] -= tangZ;
          } else {
            // Dynamic Friction: subtract a constant maximum friction
            const ratio = maxFriction / tangLen;
            this.positions[idx] -= tangX * ratio;
            this.positions[idx + 1] -= tangY * ratio;
            this.positions[idx + 2] -= tangZ * ratio;
          }
        }

        // Apply Rolling Resistance
        this.positions[idx] -= vx * TERRAIN_ROLLING_RESISTANCE;
        this.positions[idx + 1] -= vy * TERRAIN_ROLLING_RESISTANCE;
        this.positions[idx + 2] -= vz * TERRAIN_ROLLING_RESISTANCE;
      }
    }

    // 3. Hashing
    this.updateDynamicGrid();
  }

  private getHashKey(x: number, y: number, z: number): number {
    const cx = Math.floor(x / this.cellSize);
    const cy = Math.floor(y / this.cellSize);
    const cz = Math.floor(z / this.cellSize);
    // 3D Spatial hash function
    return (cx * 73856093) ^ (cy * 19349663) ^ (cz * 83492791);
  }

  public updateDynamicGrid(): void {
    this.spatialHash.clear();
    if (!this.positions) return;

    for (let i = 0; i < this.numParticles; i++) {
      if (this.isStatic[i] === 1) continue; // Skip totally pinned supports from dynamic grid

      const idx = i * 3;
      const x = this.positions[idx];
      const y = this.positions[idx + 1];
      const z = this.positions[idx + 2];

      const key = this.getHashKey(x, y, z);
      let cell = this.spatialHash.get(key);
      if (!cell) {
        cell = [];
        this.spatialHash.set(key, cell);
      }
      cell.push(i);
    }
  }

  public STRAIN_FRICTION_THRESHOLD = 0.95; // 15% stretch limit before friction breaks

  public resolveCollisions(guidebarOBB?: any, enableEndcapFriction: boolean = false, debugFriction: boolean = false, frictionDebugData?: { nodes: number[], vectors: { x: number, y: number, z: number }[] }): number {
    let totalPressure = 0;
    if (!this.positions) return 0;

    // Calculate maximum strain for friction mitigation
    let maxStrain: Float32Array | null = null;
    if (enableEndcapFriction) {
      maxStrain = new Float32Array(this.numParticles);
      for (let k = 0; k < this.springs.length; k++) {
        const s = this.springs[k];
        if (s.L0 <= 0) continue;
        const dx = this.positions[s.i1 * 3] - this.positions[s.i2 * 3];
        const dy = this.positions[s.i1 * 3 + 1] - this.positions[s.i2 * 3 + 1];
        const dz = this.positions[s.i1 * 3 + 2] - this.positions[s.i2 * 3 + 2];
        const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
        const strain = Math.abs(dist - s.L0) / s.L0;

        if (strain > maxStrain[s.i1]) maxStrain[s.i1] = strain;
        if (strain > maxStrain[s.i2]) maxStrain[s.i2] = strain;
      }
    }

    const isBoundToNextSegment = new Uint8Array(this.numParticles);
    for (let i = 0; i < this.springs.length; i++) {
      const s = this.springs[i];
      if (s.L0 > 0 && this.segmentIds[s.i1] !== this.segmentIds[s.i2]) {
        isBoundToNextSegment[s.i1] = 1;
        isBoundToNextSegment[s.i2] = 1;
      }
    }

    const endcapPlanes = new Map<number, { p0x: number, p0y: number, p0z: number, nx: number, ny: number, nz: number }>();
    for (let r = 0; r < this.numRings; r++) {
      const pithIdx = r * this.particlesPerRing;
      if (this.isEndcap[pithIdx] > 0) {
        const topIdx = pithIdx + 9 + 4;
        const rightIdx = pithIdx + 9 + 0;

        const p0x = this.positions[pithIdx * 3];
        const p0y = this.positions[pithIdx * 3 + 1];
        const p0z = this.positions[pithIdx * 3 + 2];

        const p1x = this.positions[topIdx * 3];
        const p1y = this.positions[topIdx * 3 + 1];
        const p1z = this.positions[topIdx * 3 + 2];

        const p2x = this.positions[rightIdx * 3];
        const p2y = this.positions[rightIdx * 3 + 1];
        const p2z = this.positions[rightIdx * 3 + 2];

        const v1x = p1x - p0x; const v1y = p1y - p0y; const v1z = p1z - p0z;
        const v2x = p2x - p0x; const v2y = p2y - p0y; const v2z = p2z - p0z;

        let nx = v1y * v2z - v1z * v2y;
        let ny = v1z * v2x - v1x * v2z;
        let nz = v1x * v2y - v1y * v2x;

        const len = Math.sqrt(nx * nx + ny * ny + nz * nz);
        if (len > 0.0001) { nx /= len; ny /= len; nz /= len; }

        let inwardRingIdx = -1;
        if (r === 0) inwardRingIdx = 1;
        else if (r === this.numRings - 1) inwardRingIdx = this.numRings - 2;
        else {
          if (this.segmentIds[r * this.particlesPerRing] === this.segmentIds[(r - 1) * this.particlesPerRing]) {
            inwardRingIdx = r - 1;
          } else if (this.segmentIds[r * this.particlesPerRing] === this.segmentIds[(r + 1) * this.particlesPerRing]) {
            inwardRingIdx = r + 1;
          }
        }

        if (inwardRingIdx >= 0) {
          const inwIdx = inwardRingIdx * this.particlesPerRing;
          const inwx = this.positions[inwIdx * 3];
          const inwy = this.positions[inwIdx * 3 + 1];
          const inwz = this.positions[inwIdx * 3 + 2];
          const dx = p0x - inwx;
          const dy = p0y - inwy;
          const dz = p0z - inwz;
          if (nx * dx + ny * dy + nz * dz < 0) {
            nx = -nx; ny = -ny; nz = -nz;
          }
        }
        endcapPlanes.set(r, { p0x, p0y, p0z, nx, ny, nz });
      }
    }

    const numIters = 2; // Hard cap on iterations
    const r2 = this.particleRadius * 2;

    for (let iter = 0; iter < numIters; iter++) {
      const particlePlaneHits = new Map<number, Set<number>>();
      const hasHitPlane = (particleIdx: number, ringIdx: number) => {
        const hits = particlePlaneHits.get(particleIdx);
        return hits ? hits.has(ringIdx) : false;
      };
      const recordHit = (particleIdx: number, ringIdx: number) => {
        let hits = particlePlaneHits.get(particleIdx);
        if (!hits) { hits = new Set(); particlePlaneHits.set(particleIdx, hits); }
        hits.add(ringIdx);
      };

      const checkPlaneCollision = (_particleIdx: number, planeRingIdx: number, isParticleEndcap: boolean, px: number, py: number, pz: number) => {
        const plane = endcapPlanes.get(planeRingIdx);
        if (!plane) return null;
        const dx = px - plane.p0x;
        const dy = py - plane.p0y;
        const dz = pz - plane.p0z;
        const dist = dx * plane.nx + dy * plane.ny + dz * plane.nz;

        const targetDist = isParticleEndcap ? 0.001 : this.particleRadius;

        if (dist < targetDist && dist > -this.particleRadius * 3) {
          const projX = px - plane.nx * dist;
          const projY = py - plane.ny * dist;
          const projZ = pz - plane.nz * dist;
          const radSq = (projX - plane.p0x) ** 2 + (projY - plane.p0y) ** 2 + (projZ - plane.p0z) ** 2;

          if (radSq <= this.radius * this.radius * 1.2) {
            const penetration = targetDist - dist;
            return { penetration, nx: plane.nx, ny: plane.ny, nz: plane.nz };
          }
        }
        return null;
      };

      for (let i = 0; i < this.numParticles; i++) {
        if (this.isStatic[i] === 1) continue;

        const idxI = i * 3;
        let xi = this.positions[idxI];
        let yi = this.positions[idxI + 1];
        let zi = this.positions[idxI + 2];


        // 1.5 Ramp Collision (Sphere-Wedge)
        for (const ramp of this.collisionRamps) {
          const minX = Math.min(ramp.x1, ramp.x2) - r2;
          const maxX = Math.max(ramp.x1, ramp.x2) + r2;
          const minY = Math.min(ramp.y1, ramp.y2) - r2;
          const maxY = Math.max(ramp.y1, ramp.y2) + r2;
          const minZ = Math.min(ramp.z1, ramp.z2) - r2;
          const maxZ = Math.max(ramp.z1, ramp.z2) + r2;

          if (xi >= minX && xi <= maxX && yi >= minY && yi <= maxY && zi >= minZ && zi <= maxZ) {
            const dx = ramp.x2 - ramp.x1;
            const dy = ramp.y2 - ramp.y1;
            const lenSq = dx * dx + dy * dy;

            if (lenSq > 0.0001) {
              const len = Math.sqrt(lenSq);
              let Nx = dy / len;
              let Ny = -dx / len;
              if (Ny < 0) {
                Nx = -Nx;
                Ny = -Ny;
              }

              const px = xi - ramp.x1;
              const py = yi - ramp.y1;

              const dist = px * Nx + py * Ny;
              const targetDist = this.particleRadius;

              if (dist < targetDist) {
                const sDirX = dx / len;
                const sDirY = dy / len;
                const projDist = px * sDirX + py * sDirY;

                if (projDist >= -this.particleRadius && projDist <= len + this.particleRadius) {
                  const penetration = targetDist - dist;

                  this.positions[idxI] += Nx * penetration;
                  this.positions[idxI + 1] += Ny * penetration;

                  let vx = xi - this.oldPositions[idxI];
                  let vy = yi - this.oldPositions[idxI + 1];
                  let vz = zi - this.oldPositions[idxI + 2];

                  const velAlongNormal = vx * Nx + vy * Ny;

                  if (velAlongNormal < 0) {
                    const restitutionVel = -velAlongNormal * this.restitution;
                    vx += Nx * (restitutionVel - velAlongNormal);
                    vy += Ny * (restitutionVel - velAlongNormal);

                    const tangX = vx - Nx * (vx * Nx + vy * Ny);
                    const tangY = vy - Ny * (vx * Nx + vy * Ny);

                    vx -= tangX * this.friction;
                    vy -= tangY * this.friction;
                    vz -= vz * this.friction;

                    this.oldPositions[idxI] = this.positions[idxI] - vx;
                    this.oldPositions[idxI + 1] = this.positions[idxI + 1] - vy;
                    this.oldPositions[idxI + 2] = this.positions[idxI + 2] - vz;

                    this.sleepFrames[i] = 0;
                  }

                  xi = this.positions[idxI];
                  yi = this.positions[idxI + 1];
                  zi = this.positions[idxI + 2];
                }
              }
            }
          }
        }

        // 1.6 Stump Collision
        for (const stump of this.stumps) {
          const t = stump.time > 0 ? Math.min(1.0, this.elapsedTime / stump.time) : 1.0;
          const current_z = stump.z + (stump.end_z - stump.z) * t;

          if (yi - this.particleRadius <= stump.y) {
            const dx = xi - stump.x;
            const dz = zi - current_z;
            const distSq = dx * dx + dz * dz;
            const targetDist = stump.radius + this.particleRadius;

            if (distSq < targetDist * targetDist) {
              const dist = Math.sqrt(distSq);
              let nx = 0, nz = 0;
              if (dist > 0.0001) {
                nx = dx / dist;
                nz = dz / dist;
              } else {
                nx = 1;
                nz = 0;
              }

              const penetration = targetDist - dist;
              this.positions[idxI] += nx * penetration;
              this.positions[idxI + 2] += nz * penetration;

              // Apply basic friction to damp energy during collision
              let vx = xi - this.oldPositions[idxI];
              let vy = yi - this.oldPositions[idxI + 1];
              let vz = zi - this.oldPositions[idxI + 2];

              const velAlongNormal = vx * nx + vz * nz;
              if (velAlongNormal < 0) {
                const restitutionVel = -velAlongNormal * this.restitution;
                vx += nx * (restitutionVel - velAlongNormal);
                vz += nz * (restitutionVel - velAlongNormal);

                const tangX = vx - nx * (vx * nx + vz * nz);
                const tangZ = vz - nz * (vx * nx + vz * nz);

                vx -= tangX * this.friction;
                vy -= vy * this.friction;
                vz -= tangZ * this.friction;

                this.oldPositions[idxI] = this.positions[idxI] - vx;
                this.oldPositions[idxI + 1] = this.positions[idxI + 1] - vy;
                this.oldPositions[idxI + 2] = this.positions[idxI + 2] - vz;

                this.sleepFrames[i] = 0;
              }

              xi = this.positions[idxI];
              yi = this.positions[idxI + 1];
              zi = this.positions[idxI + 2];
            }
          }
        }

        // 1.8 Guidebar OBB Rigid Body Collision
        if (guidebarOBB) {
          const C = guidebarOBB.center;
          const u = guidebarOBB.axes;
          const halfSize = guidebarOBB.collisionHalfSizes;

          const px = xi - C.x;
          const py = yi - C.y;
          const pz = zi - C.z;

          // Project point onto OBB local axes
          const localX = px * u[0].x + py * u[0].y + pz * u[0].z;
          const localY = px * u[1].x + py * u[1].y + pz * u[1].z;
          const localZ = px * u[2].x + py * u[2].y + pz * u[2].z;

          // We only pad Y and Z with particleRadius. 
          // For X (the kerf width), we use 0 padding because the endcap particles 
          // are spawned exactly on the boundary, and we don't want the guidebar 
          // pushing the log apart horizontally and destroying structural rings.
          const padX = 0.0;
          const padY = this.particleRadius;
          const padZ = this.particleRadius;

          // Check if point is inside the padded OBB
          if (Math.abs(localX) < halfSize.x + padX &&
            Math.abs(localY) < halfSize.y + padY &&
            Math.abs(localZ) < halfSize.z + padZ) {

            // It's inside! Find the axis of least penetration
            const penX = (halfSize.x + padX) - Math.abs(localX);
            const penY = (halfSize.y + padY) - Math.abs(localY);
            const penZ = (halfSize.z + padZ) - Math.abs(localZ);

            let minPen = penY;
            let normal = u[1];
            let sign = Math.sign(localY);

            if (penX < minPen) {
              minPen = penX;
              normal = u[0];
              sign = Math.sign(localX);
            }
            if (penZ < minPen) {
              minPen = penZ;
              normal = u[2];
              sign = Math.sign(localZ);
            }

            // Push particle out
            this.positions[idxI] += normal.x * sign * minPen;
            this.positions[idxI + 1] += normal.y * sign * minPen;
            this.positions[idxI + 2] += normal.z * sign * minPen;

            // Accumulate pressure only if pinching the sides of the guidebar
            if (normal === u[0]) {
              totalPressure += minPen;
            }

            // Apply friction/restitution
            let vx = xi - this.oldPositions[idxI];
            let vy = yi - this.oldPositions[idxI + 1];
            let vz = zi - this.oldPositions[idxI + 2];

            const nx = normal.x * sign;
            const ny = normal.y * sign;
            const nz = normal.z * sign;

            const velAlongNormal = vx * nx + vy * ny + vz * nz;
            if (velAlongNormal < 0) {
              const restitutionVel = -velAlongNormal * this.restitution;
              vx += nx * (restitutionVel - velAlongNormal);
              vy += ny * (restitutionVel - velAlongNormal);
              vz += nz * (restitutionVel - velAlongNormal);

              const tangX = vx - nx * (vx * nx + vy * ny + vz * nz);
              const tangY = vy - ny * (vx * nx + vy * ny + vz * nz);
              const tangZ = vz - nz * (vx * nx + vy * ny + vz * nz);

              vx -= tangX * this.friction;
              vy -= tangY * this.friction;
              vz -= tangZ * this.friction;

              this.oldPositions[idxI] = this.positions[idxI] - vx;
              this.oldPositions[idxI + 1] = this.positions[idxI + 1] - vy;
              this.oldPositions[idxI + 2] = this.positions[idxI + 2] - vz;

              this.sleepFrames[i] = 0;
            }

            xi = this.positions[idxI];
            yi = this.positions[idxI + 1];
            zi = this.positions[idxI + 2];
          }
        }


        // Only do particle collisions if not deeply sleeping to save CPU
        if (this.sleepFrames[i] > 60) continue;

        // 2. Particle-Particle Collisions (Sphere-Sphere)
        const cx = Math.floor(xi / this.cellSize);
        const cy = Math.floor(yi / this.cellSize);
        const cz = Math.floor(zi / this.cellSize);

        for (let ox = -1; ox <= 1; ox++) {
          for (let oy = -1; oy <= 1; oy++) {
            for (let oz = -1; oz <= 1; oz++) {
              const key = ((cx + ox) * 73856093) ^ ((cy + oy) * 19349663) ^ ((cz + oz) * 83492791);
              const cell = this.spatialHash.get(key);
              if (!cell) continue;

              for (let k = 0; k < cell.length; k++) {
                const j = cell[k];
                if (i >= j) continue; // avoid double checks and self checks

                // IMPORTANT: Ignore collisions within the same log segment
                const segDiff = Math.abs(this.segmentIds[i] - this.segmentIds[j]);
                if (segDiff === 0) continue;

                let targetDist = r2;

                let c_xi = xi;
                let c_yi = yi;
                let c_zi = zi;

                const idxJ = j * 3;
                let c_jx = this.positions[idxJ];
                let c_jy = this.positions[idxJ + 1];
                let c_jz = this.positions[idxJ + 2];

                const ringI = Math.floor(i / this.particlesPerRing);
                const ringJ = Math.floor(j / this.particlesPerRing);

                const isIEndcap = this.isEndcap[i] > 0;
                const isJEndcap = this.isEndcap[j] > 0;

                if (segDiff === 1 && (isIEndcap !== isJEndcap)) {
                  continue;
                }

                if (segDiff === 1 && isIEndcap && isJEndcap) {
                  if (isBoundToNextSegment[i] === 1 && isBoundToNextSegment[j] === 1) {
                    continue; // Both are uncut and bound to adjacent segments, springs will handle them.
                  }
                }

                let collisionNormal = { x: 0, y: 0, z: 0 };
                let penetration = 0;
                let usedPlaneCollision = false;

                if (isJEndcap && !hasHitPlane(i, ringJ)) {
                  const res = checkPlaneCollision(i, ringJ, isIEndcap, c_xi, c_yi, c_zi);
                  if (res) {
                    penetration = res.penetration;
                    // Normal of J points from J to I. We need normal from I to J.
                    collisionNormal = { x: -res.nx, y: -res.ny, z: -res.nz };
                    usedPlaneCollision = true;
                    recordHit(i, ringJ);
                  }
                }

                if (!usedPlaneCollision && isIEndcap && !hasHitPlane(j, ringI)) {
                  const res = checkPlaneCollision(j, ringI, isJEndcap, c_jx, c_jy, c_jz);
                  if (res) {
                    penetration = res.penetration;
                    // Normal of I points from I to J.
                    collisionNormal = { x: res.nx, y: res.ny, z: res.nz };
                    usedPlaneCollision = true;
                    recordHit(j, ringI);
                  }
                }

                if (!usedPlaneCollision) {
                  if (isIEndcap && isJEndcap) {
                    continue; // Endcap-to-Endcap collisions are strictly planar. Prevent bumpy sphere fallback.
                  }

                  if (segDiff === 1) {
                    targetDist = r2 * 0.75;
                  }
                  const dx = c_jx - c_xi;
                  const dy = c_jy - c_yi;
                  const dz = c_jz - c_zi;
                  const distSq = dx * dx + dy * dy + dz * dz;

                  const thresholdSq = targetDist * targetDist;
                  if (distSq < thresholdSq && distSq > 0.00001) {
                    const dist = Math.sqrt(distSq);
                    penetration = targetDist - dist;
                    collisionNormal = { x: dx / dist, y: dy / dist, z: dz / dist };
                  }
                }

                if (penetration > 0) {
                  // Popcorn Mitigation (Soft Correction)
                  const maxCorrection = 0.05; // Cap penetration per frame
                  const effPenetration = Math.min(penetration, maxCorrection);

                  const nx = collisionNormal.x;
                  const ny = collisionNormal.y;
                  const nz = collisionNormal.z;

                  // Position correction (push apart)
                  const w1 = this.isStatic[i] === 1 ? 0 : 1;
                  const w2 = this.isStatic[j] === 1 ? 0 : 1;
                  const wSum = w1 + w2;
                  if (wSum === 0) continue;

                  const p1 = (effPenetration * (w1 / wSum));
                  const p2 = (effPenetration * (w2 / wSum));

                  if (w1 > 0) {
                    this.positions[idxI] -= nx * p1;
                    this.positions[idxI + 1] -= ny * p1;
                    this.positions[idxI + 2] -= nz * p1;
                    this.sleepFrames[i] = 0;
                  }
                  if (w2 > 0) {
                    this.positions[idxJ] += nx * p2;
                    this.positions[idxJ + 1] += ny * p2;
                    this.positions[idxJ + 2] += nz * p2;
                    this.sleepFrames[j] = 0;
                  }

                  // Impulse application (restitution)
                  let v1x = this.positions[idxI] - this.oldPositions[idxI];
                  let v1y = this.positions[idxI + 1] - this.oldPositions[idxI + 1];
                  let v1z = this.positions[idxI + 2] - this.oldPositions[idxI + 2];

                  let v2x = this.positions[idxJ] - this.oldPositions[idxJ];
                  let v2y = this.positions[idxJ + 1] - this.oldPositions[idxJ + 1];
                  let v2z = this.positions[idxJ + 2] - this.oldPositions[idxJ + 2];

                  const rvx = v2x - v1x;
                  const rvy = v2y - v1y;
                  const rvz = v2z - v1z;

                  const velAlongNormal = rvx * nx + rvy * ny + rvz * nz;
                  if (velAlongNormal > 0) {
                    // Moving apart already, no impulse
                  } else {
                    const jMag = -(1 + this.restitution) * velAlongNormal / wSum;

                    const impulseX = nx * jMag;
                    const impulseY = ny * jMag;
                    const impulseZ = nz * jMag;

                    if (w1 > 0) {
                      v1x -= impulseX * w1;
                      v1y -= impulseY * w1;
                      v1z -= impulseZ * w1;
                      this.oldPositions[idxI] = this.positions[idxI] - v1x;
                      this.oldPositions[idxI + 1] = this.positions[idxI + 1] - v1y;
                      this.oldPositions[idxI + 2] = this.positions[idxI + 2] - v1z;
                    }

                    if (w2 > 0) {
                      v2x += impulseX * w2;
                      v2y += impulseY * w2;
                      v2z += impulseZ * w2;
                      this.oldPositions[idxJ] = this.positions[idxJ] - v2x;
                      this.oldPositions[idxJ + 1] = this.positions[idxJ + 1] - v2y;
                      this.oldPositions[idxJ + 2] = this.positions[idxJ + 2] - v2z;
                    }
                  }

                  if (enableEndcapFriction && isIEndcap && isJEndcap) {
                    const strainI = maxStrain ? maxStrain[i] : 0;
                    const strainJ = maxStrain ? maxStrain[j] : 0;

                    if (strainI < this.STRAIN_FRICTION_THRESHOLD && strainJ < this.STRAIN_FRICTION_THRESHOLD) {
                      const tangX = rvx - nx * velAlongNormal;
                      const tangY = rvy - ny * velAlongNormal;
                      const tangZ = rvz - nz * velAlongNormal;
                      const tangLen = Math.sqrt(tangX * tangX + tangY * tangY + tangZ * tangZ);

                      if (tangLen > 0.0001) {
                        // In PBD, the velocity equivalent of the positional correction (normal force) is penetration / dt.
                        const velocityFromPenetration = effPenetration / this.lastDt;
                        const normalForceProxy = Math.min(Math.max(0, -velAlongNormal) + velocityFromPenetration, 50.0);
                        const maxFriction = this.friction * normalForceProxy;

                        let fX = 0, fY = 0, fZ = 0;
                        if (tangLen <= maxFriction) {
                          fX = -tangX; fY = -tangY; fZ = -tangZ;
                        } else {
                          const ratio = maxFriction / tangLen;
                          fX = -tangX * ratio; fY = -tangY * ratio; fZ = -tangZ * ratio;
                        }

                        const pX = fX / wSum;
                        const pY = fY / wSum;
                        const pZ = fZ / wSum;

                        if (w1 > 0) {
                          v1x -= pX * w1;
                          v1y -= pY * w1;
                          v1z -= pZ * w1;
                          this.oldPositions[idxI] = this.positions[idxI] - v1x;
                          this.oldPositions[idxI + 1] = this.positions[idxI + 1] - v1y;
                          this.oldPositions[idxI + 2] = this.positions[idxI + 2] - v1z;

                          if (debugFriction && frictionDebugData) {
                            frictionDebugData.nodes.push(i);
                            frictionDebugData.vectors.push({ x: -pX * w1, y: -pY * w1, z: -pZ * w1 });
                          }
                        }
                        if (w2 > 0) {
                          v2x += pX * w2;
                          v2y += pY * w2;
                          v2z += pZ * w2;
                          this.oldPositions[idxJ] = this.positions[idxJ] - v2x;
                          this.oldPositions[idxJ + 1] = this.positions[idxJ + 1] - v2y;
                          this.oldPositions[idxJ + 2] = this.positions[idxJ + 2] - v2z;

                          if (debugFriction && frictionDebugData) {
                            frictionDebugData.nodes.push(j);
                            frictionDebugData.vectors.push({ x: pX * w2, y: pY * w2, z: pZ * w2 });
                          }
                        }
                      }
                    }
                  }

                  // Update local xi, yi, zi for next checks in this loop iteration
                  xi = this.positions[idxI];
                  yi = this.positions[idxI + 1];
                  zi = this.positions[idxI + 2];
                }
              }
            }
          }
        }
      }
    }
    return totalPressure;
  }

  /**
   * Standard 1D Spatial Hashing along the longitudinal axis (X-axis).
   */
  public insertEndcaps(R: number, t: number, normal: { x: number, y: number, z: number }, kerfWidth: number, kerfPadding: number = 0.001): number {

    const P_insert = (R + 1) * this.particlesPerRing;
    const oldNumRings = this.numRings;
    const oldNumParticles = this.numParticles;

    // 2. Resize and shift particle arrays
    const newNumParticles = oldNumParticles + 50;

    const newPositions = new Float32Array(newNumParticles * 3);
    const newOldPositions = new Float32Array(newNumParticles * 3);
    const newForces = new Float32Array(newNumParticles * 3);
    const newExternalForces = new Float32Array(newNumParticles * 3);
    const newIsStatic = new Uint8Array(newNumParticles);
    const newIsEndcap = new Uint8Array(newNumParticles);
    const newSegmentIds = new Uint16Array(newNumParticles);
    const newSleepFrames = new Uint8Array(newNumParticles);
    const newActiveSpringCount = new Uint8Array(newNumParticles);

    // Copy left part
    newPositions.set(this.positions.subarray(0, P_insert * 3), 0);
    newOldPositions.set(this.oldPositions.subarray(0, P_insert * 3), 0);
    newForces.set(this.forces.subarray(0, P_insert * 3), 0);
    newExternalForces.set(this.externalForces.subarray(0, P_insert * 3), 0);
    newIsStatic.set(this.isStatic.subarray(0, P_insert), 0);
    newIsEndcap.set(this.isEndcap.subarray(0, P_insert), 0);
    newSegmentIds.set(this.segmentIds.subarray(0, P_insert), 0);
    newSleepFrames.set(this.sleepFrames.subarray(0, P_insert), 0);
    newActiveSpringCount.set(this.activeSpringCount.subarray(0, P_insert), 0);

    // Copy right part (shifted by 50 particles = 150 floats)
    newPositions.set(this.positions.subarray(P_insert * 3, oldNumParticles * 3), (P_insert + 50) * 3);
    newOldPositions.set(this.oldPositions.subarray(P_insert * 3, oldNumParticles * 3), (P_insert + 50) * 3);
    newForces.set(this.forces.subarray(P_insert * 3, oldNumParticles * 3), (P_insert + 50) * 3);
    newExternalForces.set(this.externalForces.subarray(P_insert * 3, oldNumParticles * 3), (P_insert + 50) * 3);
    newIsStatic.set(this.isStatic.subarray(P_insert, oldNumParticles), P_insert + 50);
    newIsEndcap.set(this.isEndcap.subarray(P_insert, oldNumParticles), P_insert + 50);
    newSleepFrames.set(this.sleepFrames.subarray(P_insert, oldNumParticles), P_insert + 50);
    newActiveSpringCount.set(this.activeSpringCount.subarray(P_insert, oldNumParticles), P_insert + 50);

    // Increment segment ID for the right part to enable collisions between the two newly separated halves
    for (let k = P_insert; k < oldNumParticles; k++) {
      newSegmentIds[k + 50] = this.segmentIds[k] + 1;
    }

    // Set segment IDs for the new endcaps
    const leftSegmentId = P_insert > 0 ? this.segmentIds[P_insert - 1] : 0;
    const rightSegmentId = P_insert < oldNumParticles ? this.segmentIds[P_insert] + 1 : leftSegmentId + 1;

    for (let k = 0; k < 25; k++) newSegmentIds[P_insert + k] = leftSegmentId; // C1 attached to left
    for (let k = 0; k < 25; k++) newSegmentIds[P_insert + 25 + k] = rightSegmentId; // C2 attached to right

    for (let k = 0; k < 50; k++) newIsEndcap[P_insert + k] = 1; // Mark the two new endcaps

    this.positions = newPositions;
    this.oldPositions = newOldPositions;
    this.forces = newForces;
    this.externalForces = newExternalForces;
    this.isStatic = newIsStatic;
    this.isEndcap = newIsEndcap;
    this.segmentIds = newSegmentIds;
    this.sleepFrames = newSleepFrames;
    this.activeSpringCount = newActiveSpringCount;

    // 3. Shift spring particle indices and filter old cross-kerf springs
    for (const spring of this.springs) {
      if (spring.i1 >= P_insert) spring.i1 += 50;
      if (spring.i2 >= P_insert) spring.i2 += 50;
    }

    // Remove old springs that cross the kerf
    this.springs = this.springs.filter(s => {
      const isCross = (s.i1 < P_insert && s.i2 >= P_insert + 50) || (s.i2 < P_insert && s.i1 >= P_insert + 50);
      if (isCross) {
        if (this.activeSpringCount[s.i1] > 0) this.activeSpringCount[s.i1]--;
        if (this.activeSpringCount[s.i2] > 0) this.activeSpringCount[s.i2]--;
      }
      return !isCross;
    });

    this.numRings += 2;
    this.numParticles = newNumParticles;

    // 4. Calculate center X, Y, Z at cut by interpolating pith positions of Ring R and Ring R+3 (which was R+1)
    const idxR = R * this.particlesPerRing * 3;
    const idxR3 = (R + 3) * this.particlesPerRing * 3;

    const X_center = this.positions[idxR] + t * (this.positions[idxR3] - this.positions[idxR]);
    const Y_center = this.positions[idxR + 1] + t * (this.positions[idxR3 + 1] - this.positions[idxR + 1]);
    const Z_center = this.positions[idxR + 2] + t * (this.positions[idxR3 + 2] - this.positions[idxR + 2]);

    // 5. Generate coordinates for new endcaps C1 (index R+1) and C2 (index R+2)
    const halfWidth = kerfWidth / 2 + kerfPadding;
    const dxC1 = -halfWidth;
    const dxC2 = halfWidth;

    const Nx = normal.x;
    const Ny = normal.y;
    const Nz = normal.z;

    const setRingPositions = (ringIdx: number, dx: number) => {
      const ringOffset = ringIdx * this.particlesPerRing;

      for (let p = 0; p < this.particlesPerRing; p++) {
        const pR = (R * this.particlesPerRing + p) * 3;
        const pR3 = ((R + 3) * this.particlesPerRing + p) * 3;

        let px = this.positions[pR] + t * (this.positions[pR3] - this.positions[pR]);
        let py = this.positions[pR + 1] + t * (this.positions[pR3 + 1] - this.positions[pR + 1]);
        let pz = this.positions[pR + 2] + t * (this.positions[pR3 + 2] - this.positions[pR + 2]);

        px += Nx * dx;
        py += Ny * dx;
        pz += Nz * dx;

        const cx = X_center + Nx * dx;
        const cy = Y_center + Ny * dx;
        const cz = Z_center + Nz * dx;

        const distToPlane = (px - cx) * Nx + (py - cy) * Ny + (pz - cz) * Nz;
        px -= distToPlane * Nx;
        py -= distToPlane * Ny;
        pz -= distToPlane * Nz;

        const p3 = (ringOffset + p) * 3;
        this.positions[p3] = px;
        this.positions[p3 + 1] = py;
        this.positions[p3 + 2] = pz;
        this.oldPositions[p3] = px;
        this.oldPositions[p3 + 1] = py;
        this.oldPositions[p3 + 2] = pz;
        this.forces[p3] = 0;
        this.forces[p3 + 1] = 0;
        this.forces[p3 + 2] = 0;
        this.isStatic[ringOffset + p] = 0;
      }
    };

    setRingPositions(R + 1, dxC1);
    setRingPositions(R + 2, dxC2);

    // 5.5. Clip physical particles of adjacent rings to the cut planes to prevent mesh inversion
    const movedParticles = new Set<number>();

    // Clip Left Piece (R <= R_closest)
    const cx1 = X_center + Nx * dxC1;
    const cy1 = Y_center + Ny * dxC1;
    const cz1 = Z_center + Nz * dxC1;

    for (let r = Math.max(0, R - 2); r <= R; r++) {
      if (this.segmentIds[r * this.particlesPerRing] !== leftSegmentId) continue;

      for (let p = 0; p < this.particlesPerRing; p++) {
        const idx = r * this.particlesPerRing + p;
        let px = this.positions[idx * 3];
        let py = this.positions[idx * 3 + 1];
        let pz = this.positions[idx * 3 + 2];

        const dot = (px - cx1) * Nx + (py - cy1) * Ny + (pz - cz1) * Nz;
        if (dot > 0) { // Protruding to the right!
          px -= dot * Nx;
          py -= dot * Ny;
          pz -= dot * Nz;

          this.positions[idx * 3] = px;
          this.positions[idx * 3 + 1] = py;
          this.positions[idx * 3 + 2] = pz;
          this.oldPositions[idx * 3] = px;
          this.oldPositions[idx * 3 + 1] = py;
          this.oldPositions[idx * 3 + 2] = pz;
          movedParticles.add(idx);
        }
      }
    }

    // Clip Right Piece
    const cx2 = X_center + Nx * dxC2;
    const cy2 = Y_center + Ny * dxC2;
    const cz2 = Z_center + Nz * dxC2;

    for (let r = R + 3; r <= Math.min(this.numRings - 1, R + 5); r++) {
      if (this.segmentIds[r * this.particlesPerRing] !== rightSegmentId) continue;

      for (let p = 0; p < this.particlesPerRing; p++) {
        const idx = r * this.particlesPerRing + p;
        let px = this.positions[idx * 3];
        let py = this.positions[idx * 3 + 1];
        let pz = this.positions[idx * 3 + 2];

        const dot = (px - cx2) * Nx + (py - cy2) * Ny + (pz - cz2) * Nz;
        if (dot < 0) { // Protruding to the left!
          px -= dot * Nx;
          py -= dot * Ny;
          pz -= dot * Nz;

          this.positions[idx * 3] = px;
          this.positions[idx * 3 + 1] = py;
          this.positions[idx * 3 + 2] = pz;
          this.oldPositions[idx * 3] = px;
          this.oldPositions[idx * 3 + 1] = py;
          this.oldPositions[idx * 3 + 2] = pz;
          movedParticles.add(idx);
        }
      }
    }

    // 5.6. Update L0 for existing springs connected to clipped particles
    for (const spring of this.springs) {
      if (spring.L0 < 0) continue;
      if (movedParticles.has(spring.i1) || movedParticles.has(spring.i2)) {
        const idx1 = spring.i1 * 3;
        const idx2 = spring.i2 * 3;
        const dx = this.positions[idx1] - this.positions[idx2];
        const dy = this.positions[idx1 + 1] - this.positions[idx2 + 1];
        const dz = this.positions[idx1 + 2] - this.positions[idx2 + 2];
        spring.L0 = Math.sqrt(dx * dx + dy * dy + dz * dz);
      }
    }

    // 6. Helper to add a spring and calculate rest length dynamically
    const addSpring = (i1: number, i2: number, k: number) => {
      const idx1 = i1 * 3;
      const idx2 = i2 * 3;
      const dx = this.positions[idx1] - this.positions[idx2];
      const dy = this.positions[idx1 + 1] - this.positions[idx2 + 1];
      const dz = this.positions[idx1 + 2] - this.positions[idx2 + 2];
      const L0 = Math.sqrt(dx * dx + dy * dy + dz * dz);
      this.springs.push({ i1, i2, L0, k });
      this.activeSpringCount[i1]++;
      this.activeSpringCount[i2]++;
    };

    // 7. Connect Springs for C1 (R+1) and C2 (R+2)
    const connectRingSprings = (ringIdx: number) => {
      const ringOffset = ringIdx * this.particlesPerRing;

      // Intra-ring circumferential Lane 1
      for (let i = 0; i < 8; i++) {
        addSpring(ringOffset + 1 + i, ringOffset + 1 + ((i + 1) % 8), this.kStructural);
      }
      // Intra-ring circumferential Lane 2
      for (let i = 0; i < 16; i++) {
        addSpring(ringOffset + 9 + i, ringOffset + 9 + ((i + 1) % 16), this.kStructural);
      }
      // Radial Pith to Lane 1
      for (let i = 0; i < 8; i++) {
        addSpring(ringOffset, ringOffset + 1 + i, this.kStructural);
      }
      // Radial Lane 1 to Lane 2
      for (let i = 0; i < 8; i++) {
        addSpring(ringOffset + 1 + i, ringOffset + 9 + (2 * i), this.kStructural);
        addSpring(ringOffset + 1 + i, ringOffset + 9 + ((2 * i + 1) % 16), this.kStructural);
      }

      // Intra-ring Shear (Diagonal Bracing)
      for (let i = 0; i < 8; i++) {
        const next = (i + 1) % 8;
        addSpring(ringOffset + 1 + i, ringOffset + 9 + (2 * next), this.kShear);
        addSpring(ringOffset + 1 + next, ringOffset + 9 + (2 * i + 1), this.kShear);
      }
    };

    connectRingSprings(R + 1); // C1
    connectRingSprings(R + 2); // C2

    // 8. Connect C1 to left neighbor Ring R
    const rLeft = R * this.particlesPerRing;
    const rC1 = (R + 1) * this.particlesPerRing;

    // Grain (Structural)
    for (let i = 0; i < this.particlesPerRing; i++) {
      addSpring(rLeft + i, rC1 + i, this.kStructural);
    }
    // Shear Lane 1
    for (let i = 0; i < 8; i++) {
      const next = (i + 1) % 8;
      addSpring(rLeft + 1 + i, rC1 + 1 + next, this.kShear);
      addSpring(rLeft + 1 + next, rC1 + 1 + i, this.kShear);
    }
    // Shear Lane 2
    for (let i = 0; i < 16; i++) {
      const next = (i + 1) % 16;
      addSpring(rLeft + 9 + i, rC1 + 9 + next, this.kShear);
      addSpring(rLeft + 9 + next, rC1 + 9 + i, this.kShear);
    }
    // Shear Pith <-> Lane 1
    for (let i = 0; i < 8; i++) {
      addSpring(rLeft, rC1 + 1 + i, this.kShear);
      addSpring(rC1, rLeft + 1 + i, this.kShear);
    }
    // Shear Lane 1 <-> Lane 2
    for (let i = 0; i < 8; i++) {
      const outer1 = 2 * i;
      const outer2 = (2 * i + 1) % 16;
      addSpring(rLeft + 1 + i, rC1 + 9 + outer1, this.kShear);
      addSpring(rLeft + 1 + i, rC1 + 9 + outer2, this.kShear);
      addSpring(rC1 + 1 + i, rLeft + 9 + outer1, this.kShear);
      addSpring(rC1 + 1 + i, rLeft + 9 + outer2, this.kShear);
    }

    // 9. Connect C2 to right neighbor Ring R+3
    const rC2 = (R + 2) * this.particlesPerRing;
    const rRight = (R + 3) * this.particlesPerRing;

    // Grain (Structural)
    for (let i = 0; i < this.particlesPerRing; i++) {
      addSpring(rC2 + i, rRight + i, this.kStructural);
    }
    // Shear Lane 1
    for (let i = 0; i < 8; i++) {
      const next = (i + 1) % 8;
      addSpring(rC2 + 1 + i, rRight + 1 + next, this.kShear);
      addSpring(rC2 + 1 + next, rRight + 1 + i, this.kShear);
    }
    // Shear Lane 2
    for (let i = 0; i < 16; i++) {
      const next = (i + 1) % 16;
      addSpring(rC2 + 9 + i, rRight + 9 + next, this.kShear);
      addSpring(rC2 + 9 + next, rRight + 9 + i, this.kShear);
    }
    // Shear Pith <-> Lane 1
    for (let i = 0; i < 8; i++) {
      addSpring(rC2, rRight + 1 + i, this.kShear);
      addSpring(rRight, rC2 + 1 + i, this.kShear);
    }
    // Shear Lane 1 <-> Lane 2
    for (let i = 0; i < 8; i++) {
      const outer1 = 2 * i;
      const outer2 = (2 * i + 1) % 16;
      addSpring(rC2 + 1 + i, rRight + 9 + outer1, this.kShear);
      addSpring(rC2 + 1 + i, rRight + 9 + outer2, this.kShear);
      addSpring(rRight + 1 + i, rC2 + 9 + outer1, this.kShear);
      addSpring(rRight + 1 + i, rC2 + 9 + outer2, this.kShear);
    }

    // 10. Bending / skip-grain springs
    // Left side (if R > 0): connect Ring R-1 to C1
    if (R > 0) {
      const rSkipLeft = (R - 1) * this.particlesPerRing;
      for (let i = 0; i < this.particlesPerRing; i++) {
        addSpring(rSkipLeft + i, rC1 + i, this.kBending);
      }
    }
    // Right side (if R + 3 < oldNumRings - 1): connect C2 to Ring R+4
    if (R + 3 < oldNumRings - 1) {
      const rSkipRight = (R + 4) * this.particlesPerRing;
      for (let i = 0; i < this.particlesPerRing; i++) {
        addSpring(rC2 + i, rSkipRight + i, this.kBending);
      }
    }

    // 10.5. Add Kerf springs directly connecting C1 and C2
    // Structural C1 to C2
    for (let i = 0; i < this.particlesPerRing; i++) {
      addSpring(rC1 + i, rC2 + i, this.kStructural);
    }
    // Shear C1 to C2
    for (let i = 0; i < 8; i++) {
      const next = (i + 1) % 8;
      addSpring(rC1 + 1 + i, rC2 + 1 + next, this.kShear);
      addSpring(rC1 + 1 + next, rC2 + 1 + i, this.kShear);
    }
    for (let i = 0; i < 16; i++) {
      const next = (i + 1) % 16;
      addSpring(rC1 + 9 + i, rC2 + 9 + next, this.kShear);
      addSpring(rC1 + 9 + next, rC2 + 9 + i, this.kShear);
    }
    // Pith to Lane 1 shear
    for (let i = 0; i < 8; i++) {
      addSpring(rC1, rC2 + 1 + i, this.kShear);
      addSpring(rC2, rC1 + 1 + i, this.kShear);
    }
    // Lane 1 to Lane 2 shear
    for (let i = 0; i < 8; i++) {
      const outer1 = 2 * i;
      const outer2 = (2 * i + 1) % 16;
      addSpring(rC1 + 1 + i, rC2 + 9 + outer1, this.kShear);
      addSpring(rC1 + 1 + i, rC2 + 9 + outer2, this.kShear);
      addSpring(rC2 + 1 + i, rC1 + 9 + outer1, this.kShear);
      addSpring(rC2 + 1 + i, rC1 + 9 + outer2, this.kShear);
    }
    // Kerf Bending springs bracing across the kerf
    for (let i = 0; i < this.particlesPerRing; i++) {
      addSpring(rLeft + i, rC2 + i, this.kBending);
      addSpring(rC1 + i, rRight + i, this.kBending);
    }

    // 11. Adjust L0 for springs crossing the kerf
    for (const spring of this.springs) {
      if (spring.L0 < 0) continue;
      if (movedParticles.has(spring.i1) || movedParticles.has(spring.i2)) {
        const idx1 = spring.i1 * 3;
        const idx2 = spring.i2 * 3;
        const dx = this.positions[idx1] - this.positions[idx2];
        const dy = this.positions[idx1 + 1] - this.positions[idx2 + 1];
        const dz = this.positions[idx1 + 2] - this.positions[idx2 + 2];
        spring.L0 = Math.sqrt(dx * dx + dy * dy + dz * dz);
      }
    }

    this.updateDynamicGrid();
    return R;
  }
}
